  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = *conn_result;

  // Use sqlgen's write function to perform upsert operation
  // The write function handles both insert and update based on primary key constraints
  auto write_result = sqlgen::write(conn, u);

  // Check if the write operation was successful
  if (write_result) {
    return true; // Success
