    // If write failed, attempt to update the existing record
    // Create update statement using sqlgen's update function
    auto update_stmt = sqlgen::update<UserProfile>(
        sqlgen::set("bio"_c = u.bio),
        sqlgen::set("avatar_url"_c = u.avatar_url)
    ) | sqlgen::where("user_id"_c == u.user_id);

    // Execute the update statement
    auto update_result = update_stmt(conn);
    return update_result;
  }
}

