  auto query = sqlgen::read<std::vector<A>>
               | sqlgen::join<B, "t2">("id"_t1 == "a_id"_t2)
               | sqlgen::where(("score"_t2 > 10) && ("name"_t1.like("%x%")))
               | sqlgen::order_by("score"_t2.desc())
               | sqlgen::limit(5);

