  EXPECT_DOUBLE_EQ(m1.tax_rate, 5.0);

  const auto& m2 = metrics[1];
  EXPECT_EQ(m2.item_id, 2);
  EXPECT_DOUBLE_EQ(m2.gross_total, 600.0);
  EXPECT_DOUBLE_EQ(m2.discounted_total, 600.0);
